+import { describe, it, expect, beforeEach } from 'vitest';
+import { Database } from '../../src/utils/database.js';
+import { EventBus } from '../../src/events/event-bus.js';
+import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
+
+import { UserRepository } from '../../src/repositories/user.repository.js';
+import { OrderRepository } from '../../src/repositories/order.repository.js';
+import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
+import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
+
+import { UserService, resetUserIdCounter } from '../../src/services/user.service.js';
+import { OrderService, resetOrderIdCounter } from '../../src/services/order.service.js';
+import { PreferencesService, resetPreferencesIdCounter } from '../../src/services/preferences.service.js';
+import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
+import { NotificationHistoryService, resetLogIdCounter } from '../../src/services/notification-history.service.js';
+
+import { EmailAdapter } from '../../src/adapters/email-adapter.js';
+import { SmsAdapter } from '../../src/adapters/sms-adapter.js';
+import { WebhookAdapter } from '../../src/adapters/webhook-adapter.js';
+
+describe('Notification Pipeline Integration', () => {
+  let db: Database;
+  let eventBus: EventBus;
+
+  let userRepo: UserRepository;
+  let orderRepo: OrderRepository;
+  let prefsRepo: PreferencesRepository;
+  let notifLogRepo: NotificationLogRepository;
+
+  let userService: UserService;
+  let orderService: OrderService;
+  let preferencesService: PreferencesService;
+  let notificationService: NotificationService;
+  let historyService: NotificationHistoryService;
+
+  let emailAdapter: EmailAdapter;
+  let smsAdapter: SmsAdapter;
+  let webhookAdapter: WebhookAdapter;
+
+  beforeEach(() => {
+    // Reset all state
+    db = new Database();
+    eventBus = new EventBus();
+    statusChangeCallbacks.clear();
+    resetUserIdCounter();
+    resetOrderIdCounter();
+    resetPreferencesIdCounter();
+    resetNotificationIdCounter();
+    resetLogIdCounter();
+
+    // Repositories
+    userRepo = new UserRepository(db);
+    orderRepo = new OrderRepository(db);
+    prefsRepo = new PreferencesRepository(db);
+    notifLogRepo = new NotificationLogRepository(db);
+
+    // Adapters
+    emailAdapter = new EmailAdapter({
+      from: 'noreply@taskflow.local',
+      recipientMap: {},
+    });
+    smsAdapter = new SmsAdapter({
+      from: '+10000000000',
+      recipientMap: {},
+    });
+    webhookAdapter = new WebhookAdapter({
+      url: 'https://hooks.example.com/notify',
+    });
+
+    // Services
+    userService = new UserService(userRepo, eventBus);
+    orderService = new OrderService(orderRepo, userRepo, eventBus);
+    preferencesService = new PreferencesService(prefsRepo, userRepo);
+    historyService = new NotificationHistoryService(notifLogRepo);
+
+    // Wire up notification service with all adapters
+    notificationService = new NotificationService(eventBus, [
+      emailAdapter,
+      smsAdapter,
+      webhookAdapter,
+    ]);
+    notificationService.setPreferencesService(preferencesService);
+    notificationService.setHistoryService(historyService);
+  });
+
+  describe('email notification with preferences enabled', () => {
+    it('should deliver email notification when user creates an order', async () => {
+      const user = await userService.createUser({
+        name: 'Alice',
+        email: 'alice@example.com',
+        role: 'member',
+      });
+
+      // Ensure default preferences (all enabled)
+      preferencesService.getOrCreatePreferences(user.id);
+
+      const order = await orderService.createOrder({
+        userId: user.id,
+        items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 15 }],
+      });
+
+      // Email adapter should have received the notification
+      const emails = emailAdapter.getOutbox();
+      expect(emails).toHaveLength(1);
+      expect(emails[0]!.to).toBe('alice@example.com');
+      expect(emails[0]!.subject).toContain('Order Confirmation');
+      expect(emails[0]!.html).toContain('Widget x2');
+      expect(emails[0]!.html).toContain('$30.00');
+    });
+
+    it('should deliver email for order status changes', async () => {
+      const user = await userService.createUser({
+        name: 'Bob',
+        email: 'bob@example.com',
+        role: 'member',
+      });
+
+      // Set up recipient map so SMS adapter can resolve userId to phone
+      smsAdapter = new SmsAdapter({
+        recipientMap: { [user.id]: '+15551234567' },
+      });
+
+      // Recreate notification service with updated SMS adapter
+      statusChangeCallbacks.clear();
+      resetNotificationIdCounter();
+      notificationService = new NotificationService(eventBus, [
+        emailAdapter,
+        smsAdapter,
+        webhookAdapter,
+      ]);
+      notificationService.setPreferencesService(preferencesService);
+      notificationService.setHistoryService(historyService);
+
+      preferencesService.getOrCreatePreferences(user.id);
+
+      const order = await orderService.createOrder({
+        userId: user.id,
+        items: [{ productId: 'p1', name: 'Gadget', quantity: 1, unitPrice: 50 }],
+      });
+
+      // Clear adapters to isolate status change notification
+      emailAdapter.clearOutbox();
+
+      await orderService.updateOrderStatus(order.id, 'confirmed');
+
+      const emails = emailAdapter.getOutbox();
+      expect(emails).toHaveLength(1);
+      expect(emails[0]!.subject).toContain('Order Update');
+      expect(emails[0]!.html).toContain('pending');
+      expect(emails[0]!.html).toContain('confirmed');
+    });
+  });
+
+  describe('SMS notification with preferences enabled', () => {
+    it('should deliver SMS notification when order is created', async () => {
+      const user = await userService.createUser({
+        name: 'Carol',
+        email: 'carol@example.com',
+        role: 'member',
+      });
+
+      preferencesService.getOrCreatePreferences(user.id);
+
+      await orderService.createOrder({
+        userId: user.id,
+        items: [{ productId: 'p1', name: 'Phone Case', quantity: 3, unitPrice: 12 }],
+      });
+
+      // SMS adapter should have received the notification
+      const smsMessages = smsAdapter.getSentMessages();
+      expect(smsMessages).toHaveLength(1);
+      expect(smsMessages[0]!.body).toContain('Order Confirmation');
+      expect(smsMessages[0]!.body).toContain('Phone Case x3');
+    });
+
+    it('should deliver SMS for status changes with resolved phone number', async () => {
+      // Set up SMS adapter with recipient map
+      const phoneSmsAdapter = new SmsAdapter({
+        recipientMap: { 'user-0001': '+15559876543' },
+      });
+
+      statusChangeCallbacks.clear();
+      resetNotificationIdCounter();
+      notificationService = new NotificationService(eventBus, [phoneSmsAdapter]);
+      notificationService.setPreferencesService(preferencesService);
+      notificationService.setHistoryService(historyService);
+
+      const user = await userService.createUser({
+        name: 'Dan',
+        email: 'dan@example.com',
+        role: 'member',
+      });
+
+      preferencesService.getOrCreatePreferences(user.id);
+
+      const order = await orderService.createOrder({
+        userId: user.id,
+        items: [{ productId: 'p1', name: 'Cable', quantity: 1, unitPrice: 8 }],
+      });
+
+      // Clear to isolate status change
+      phoneSmsAdapter.clearSentMessages();
+
+      await orderService.updateOrderStatus(order.id, 'confirmed');
+
+      const smsMessages = phoneSmsAdapter.getSentMessages();
+      expect(smsMessages).toHaveLength(1);
+      expect(smsMessages[0]!.to).toBe('+15559876543');
+      expect(smsMessages[0]!.body).toContain('pending');
+      expect(smsMessages[0]!.body).toContain('confirmed');
+    });
+  });
+
+  describe('webhook notification', () => {
+    it('should deliver webhook notification when order is created', async () => {
+      const user = await userService.createUser({
+        name: 'Eve',
+        email: 'eve@example.com',
+        role: 'member',
+      });
+
+      preferencesService.getOrCreatePreferences(user.id);
+
+      await orderService.createOrder({
+        userId: user.id,
+        items: [{ productId: 'p1', name: 'Keyboard', quantity: 1, unitPrice: 75 }],
+      });
+
+      const deliveries = webhookAdapter.getDeliveries();
+      expect(deliveries).toHaveLength(1);
+      expect(deliveries[0]!.url).toBe('https://hooks.example.com/notify');
+      expect(deliveries[0]!.payload.recipient).toBe('eve@example.com');
+      expect(deliveries[0]!.payload.subject).toContain('Order Confirmation');
+      expect(deliveries[0]!.payload.body).toContain('Keyboard x1');
+    });
+
+    it('should deliver webhook for order status changes', async () => {
+      const user = await userService.createUser({
+        name: 'Frank',
+        email: 'frank@example.com',
+        role: 'member',
+      });
+
+      preferencesService.getOrCreatePreferences(user.id);
+
+      const order = await orderService.createOrder({
+        userId: user.id,
+        items: [{ productId: 'p1', name: 'Mouse', quantity: 1, unitPrice: 25 }],
+      });
+
+      webhookAdapter.clearDeliveries();
+
+      await orderService.updateOrderStatus(order.id, 'confirmed');
+
+      const deliveries = webhookAdapter.getDeliveries();
+      expect(deliveries).toHaveLength(1);
+      expect(deliveries[0]!.payload.subject).toContain('Order Update');
+      expect(deliveries[0]!.payload.body).toContain('pending');
+      expect(deliveries[0]!.payload.body).toContain('confirmed');
+    });
+  });
+
+  describe('notification history logging', () => {
+    it('should log notifications to history for each adapter', async () => {
+      const user = await userService.createUser({
+        name: 'Grace',
+        email: 'grace@example.com',
+        role: 'member',
+      });
+
+      preferencesService.getOrCreatePreferences(user.id);
+
+      await orderService.createOrder({
+        userId: user.id,
+        items: [{ productId: 'p1', name: 'Monitor', quantity: 1, unitPrice: 300 }],
+      });
+
+      // Should have one log per adapter (email, sms, webhook)
+      expect(historyService.count()).toBe(3);
+
+      const emailLogs = historyService.query({ channel: 'email' });
+      expect(emailLogs).toHaveLength(1);
+      expect(emailLogs[0]!.recipient).toBe('grace@example.com');
+      expect(emailLogs[0]!.type).toBe('order_confirmation');
+      expect(emailLogs[0]!.status).toBe('sent');
+
+      const smsLogs = historyService.query({ channel: 'sms' });
+      expect(smsLogs).toHaveLength(1);
+      expect(smsLogs[0]!.status).toBe('sent');
+
+      const webhookLogs = historyService.query({ channel: 'webhook' });
+      expect(webhookLogs).toHaveLength(1);
+      expect(webhookLogs[0]!.status).toBe('sent');
+    });
+
+    it('should log history for status change notifications', async () => {
+      const user = await userService.createUser({
+        name: 'Hank',
+        email: 'hank@example.com',
+        role: 'member',
+      });
+
+      preferencesService.getOrCreatePreferences(user.id);
+
+      const order = await orderService.createOrder({
+        userId: user.id,
+        items: [{ productId: 'p1', name: 'Desk', quantity: 1, unitPrice: 200 }],
+      });
+
+      // 3 logs from order creation (one per adapter)
+      expect(historyService.count()).toBe(3);
+
+      await orderService.updateOrderStatus(order.id, 'confirmed');
+
+      // 3 more logs from status change
+      expect(historyService.count()).toBe(6);
+
+      const statusLogs = historyService.query({ type: 'order_status_update' });
+      expect(statusLogs).toHaveLength(3);
+      for (const log of statusLogs) {
+        expect(log.subject).toContain('Order Update');
+        expect(log.status).toBe('sent');
+      }
+    });
+
+    it('should be queryable by recipient', async () => {
+      const user = await userService.createUser({
+        name: 'Irene',
+        email: 'irene@example.com',
+        role: 'member',
+      });
+
+      preferencesService.getOrCreatePreferences(user.id);
+
+      await orderService.createOrder({
+        userId: user.id,
+        items: [{ productId: 'p1', name: 'Lamp', quantity: 1, unitPrice: 40 }],
+      });
+
+      const logs = historyService.getByRecipient('irene@example.com');
+      expect(logs).toHaveLength(3);
+    });
+  });
+
+  describe('user preferences enforcement', () => {
+    it('should not send notifications when email is disabled', async () => {
+      const user = await userService.createUser({
+        name: 'Jake',
+        email: 'jake@example.com',
+        role: 'member',
+      });
+
+      // Disable email notifications
+      preferencesService.updateEmailPreferences(user.id, { enabled: false });
+
+      await orderService.createOrder({
+        userId: user.id,
+        items: [{ productId: 'p1', name: 'Chair', quantity: 1, unitPrice: 150 }],
+      });
+
+      // No notifications should have been sent
+      expect(notificationService.getNotificationCount()).toBe(0);
+      expect(emailAdapter.getOutbox()).toHaveLength(0);
+      expect(smsAdapter.getSentMessages()).toHaveLength(0);
+      expect(webhookAdapter.getDeliveries()).toHaveLength(0);
+      expect(historyService.count()).toBe(0);
+    });
+
+    it('should not send when frequency is not immediate', async () => {
+      const user = await userService.createUser({
+        name: 'Kate',
+        email: 'kate@example.com',
+        role: 'member',
+      });
+
+      preferencesService.updateEmailPreferences(user.id, {
+        frequency: 'daily_digest',
+      });
+
+      await orderService.createOrder({
+        userId: user.id,
+        items: [{ productId: 'p1', name: 'Table', quantity: 1, unitPrice: 250 }],
+      });
+
+      expect(notificationService.getNotificationCount()).toBe(0);
+      expect(emailAdapter.getOutbox()).toHaveLength(0);
+    });
+
+    it('should not send when category is unsubscribed', async () => {
+      const user = await userService.createUser({
+        name: 'Leo',
+        email: 'leo@example.com',
+        role: 'member',
+      });
+
+      // Subscribe only to order_status_update, not order_confirmation
+      preferencesService.updateEmailPreferences(user.id, {
+        subscribedCategories: ['order_status_update'],
+      });
+
+      await orderService.createOrder({
+        userId: user.id,
+        items: [{ productId: 'p1', name: 'Shelf', quantity: 1, unitPrice: 60 }],
+      });
+
+      // Order creation notification should be skipped (order_confirmation not subscribed)
+      expect(notificationService.getNotificationCount()).toBe(0);
+      expect(emailAdapter.getOutbox()).toHaveLength(0);
+    });
+
+    it('should send status updates when only that category is subscribed', async () => {
+      const user = await userService.createUser({
+        name: 'Mia',
+        email: 'mia@example.com',
+        role: 'member',
+      });
+
+      // Subscribe only to status updates
+      preferencesService.updateEmailPreferences(user.id, {
+        subscribedCategories: ['order_status_update'],
+      });
+
+      // Order creation should be skipped
+      const order = await orderService.createOrder({
+        userId: user.id,
+        items: [{ productId: 'p1', name: 'Rug', quantity: 1, unitPrice: 80 }],
+      });
+
+      expect(notificationService.getNotificationCount()).toBe(0);
+
+      // But status change should go through
+      await orderService.updateOrderStatus(order.id, 'confirmed');
+
+      expect(notificationService.getNotificationCount()).toBe(1);
+      expect(emailAdapter.getOutbox()).toHaveLength(1);
+    });
+
+    it('should send all notifications when no preferences are set (defaults)', async () => {
+      const user = await userService.createUser({
+        name: 'Nate',
+        email: 'nate@example.com',
+        role: 'member',
+      });
+
+      // Don't create preferences at all — defaults allow everything
+
+      await orderService.createOrder({
+        userId: user.id,
+        items: [{ productId: 'p1', name: 'Pen', quantity: 5, unitPrice: 2 }],
+      });
+
+      expect(notificationService.getNotificationCount()).toBe(1);
+      expect(emailAdapter.getOutbox()).toHaveLength(1);
+    });
+
+    it('should block status change notifications when disabled', async () => {
+      const user = await userService.createUser({
+        name: 'Olivia',
+        email: 'olivia@example.com',
+        role: 'member',
+      });
+
+      const order = await orderService.createOrder({
+        userId: user.id,
+        items: [{ productId: 'p1', name: 'Book', quantity: 1, unitPrice: 20 }],
+      });
+
+      // Now disable email
+      preferencesService.updateEmailPreferences(user.id, { enabled: false });
+
+      // Clear state from order creation
+      emailAdapter.clearOutbox();
+      notificationService.clearNotifications();
+
+      await orderService.updateOrderStatus(order.id, 'confirmed');
+
+      expect(notificationService.getNotificationCount()).toBe(0);
+      expect(emailAdapter.getOutbox()).toHaveLength(0);
+    });
+  });
+
+  describe('notification ordering', () => {
+    it('should maintain order across creation and status updates', async () => {
+      const user = await userService.createUser({
+        name: 'Paul',
+        email: 'paul@example.com',
+        role: 'member',
+      });
+
+      preferencesService.getOrCreatePreferences(user.id);
+
+      const order = await orderService.createOrder({
+        userId: user.id,
+        items: [{ productId: 'p1', name: 'Speaker', quantity: 1, unitPrice: 100 }],
+      });
+
+      await orderService.updateOrderStatus(order.id, 'confirmed');
+      await orderService.updateOrderStatus(order.id, 'shipped');
+
+      const notifications = notificationService.getNotifications();
+      expect(notifications).toHaveLength(3);
+
+      // First: order confirmation
+      expect(notifications[0]!.subject).toContain('Order Confirmation');
+      // Second: pending -> confirmed
+      expect(notifications[1]!.subject).toContain('Order Update');
+      expect(notifications[1]!.body).toContain('pending');
+      expect(notifications[1]!.body).toContain('confirmed');
+      // Third: confirmed -> shipped
+      expect(notifications[2]!.subject).toContain('Order Update');
+      expect(notifications[2]!.body).toContain('confirmed');
+      expect(notifications[2]!.body).toContain('shipped');
+
+      // IDs should be sequential
+      expect(notifications[0]!.id).toBe('notif-0001');
+      expect(notifications[1]!.id).toBe('notif-0002');
+      expect(notifications[2]!.id).toBe('notif-0003');
+    });
+
+    it('should maintain order in history logs', async () => {
+      // Use only email adapter for simpler history tracking
+      statusChangeCallbacks.clear();
+      resetNotificationIdCounter();
+      resetLogIdCounter();
+
+      const soloEmailAdapter = new EmailAdapter();
+      notificationService = new NotificationService(eventBus, [soloEmailAdapter]);
+      notificationService.setPreferencesService(preferencesService);
+      notificationService.setHistoryService(historyService);
+
+      const user = await userService.createUser({
+        name: 'Quinn',
+        email: 'quinn@example.com',
+        role: 'member',
+      });
+
+      preferencesService.getOrCreatePreferences(user.id);
+
+      const order = await orderService.createOrder({
+        userId: user.id,
+        items: [{ productId: 'p1', name: 'Headphones', quantity: 1, unitPrice: 50 }],
+      });
+
+      await orderService.updateOrderStatus(order.id, 'confirmed');
+
+      const logs = historyService.query({});
+      expect(logs).toHaveLength(2);
+      expect(logs[0]!.type).toBe('order_confirmation');
+      expect(logs[1]!.type).toBe('order_status_update');
+
+      // Log IDs should be sequential
+      expect(logs[0]!.id).toBe('nlog-0001');
+      expect(logs[1]!.id).toBe('nlog-0002');
+    });
+
+    it('should deliver to all adapters for each notification', async () => {
+      const user = await userService.createUser({
+        name: 'Rosa',
+        email: 'rosa@example.com',
+        role: 'member',
+      });
+
+      preferencesService.getOrCreatePreferences(user.id);
+
+      await orderService.createOrder({
+        userId: user.id,
+        items: [{ productId: 'p1', name: 'Tablet', quantity: 1, unitPrice: 400 }],
+      });
+
+      // Each adapter should have exactly one delivery
+      expect(emailAdapter.getOutbox()).toHaveLength(1);
+      expect(smsAdapter.getSentMessages()).toHaveLength(1);
+      expect(webhookAdapter.getDeliveries()).toHaveLength(1);
+
+      // But the notification service only records one logical notification
+      expect(notificationService.getNotificationCount()).toBe(1);
+    });
+  });
+
+  describe('multiple users and orders', () => {
+    it('should track notifications for different users independently', async () => {
+      const alice = await userService.createUser({
+        name: 'Alice',
+        email: 'alice@test.com',
+        role: 'member',
+      });
+      const bob = await userService.createUser({
+        name: 'Bob',
+        email: 'bob@test.com',
+        role: 'member',
+      });
+
+      preferencesService.getOrCreatePreferences(alice.id);
+      preferencesService.getOrCreatePreferences(bob.id);
+
+      await orderService.createOrder({
+        userId: alice.id,
+        items: [{ productId: 'p1', name: 'Item A', quantity: 1, unitPrice: 10 }],
+      });
+      await orderService.createOrder({
+        userId: bob.id,
+        items: [{ productId: 'p2', name: 'Item B', quantity: 2, unitPrice: 20 }],
+      });
+
+      expect(notificationService.getNotificationsForRecipient('alice@test.com')).toHaveLength(1);
+      expect(notificationService.getNotificationsForRecipient('bob@test.com')).toHaveLength(1);
+      expect(notificationService.getNotificationCount()).toBe(2);
+
+      const aliceLogs = historyService.getByRecipient('alice@test.com');
+      const bobLogs = historyService.getByRecipient('bob@test.com');
+      expect(aliceLogs).toHaveLength(3); // one per adapter
+      expect(bobLogs).toHaveLength(3);
+    });
+
+    it('should respect per-user preferences', async () => {
+      const alice = await userService.createUser({
+        name: 'Alice',
+        email: 'alice2@test.com',
+        role: 'member',
+      });
+      const bob = await userService.createUser({
+        name: 'Bob',
+        email: 'bob2@test.com',
+        role: 'member',
+      });
+
+      // Alice has notifications enabled
+      preferencesService.getOrCreatePreferences(alice.id);
+
+      // Bob has notifications disabled
+      preferencesService.updateEmailPreferences(bob.id, { enabled: false });
+
+      await orderService.createOrder({
+        userId: alice.id,
+        items: [{ productId: 'p1', name: 'Item A', quantity: 1, unitPrice: 10 }],
+      });
+      await orderService.createOrder({
+        userId: bob.id,
+        items: [{ productId: 'p2', name: 'Item B', quantity: 1, unitPrice: 20 }],
+      });
+
+      // Only Alice should get notifications
+      expect(notificationService.getNotificationsForRecipient('alice2@test.com')).toHaveLength(1);
+      expect(notificationService.getNotificationsForRecipient('bob2@test.com')).toHaveLength(0);
+      expect(notificationService.getNotificationCount()).toBe(1);
+    });
+  });
+
+  describe('full order lifecycle', () => {
+    it('should send notifications through the complete order lifecycle', async () => {
+      const user = await userService.createUser({
+        name: 'Zara',
+        email: 'zara@example.com',
+        role: 'member',
+      });
+
+      preferencesService.getOrCreatePreferences(user.id);
+
+      // Create order
+      const order = await orderService.createOrder({
+        userId: user.id,
+        items: [
+          { productId: 'p1', name: 'Laptop', quantity: 1, unitPrice: 999 },
+          { productId: 'p2', name: 'Charger', quantity: 2, unitPrice: 29 },
+        ],
+      });
+
+      // Progress through lifecycle
+      await orderService.updateOrderStatus(order.id, 'confirmed');
+      await orderService.updateOrderStatus(order.id, 'shipped');
+      await orderService.updateOrderStatus(order.id, 'delivered');
